CREATE TABLE branches (id BIGINT IDENTITY(1,1) PRIMARY KEY, branch_code VARCHAR(20) NOT NULL UNIQUE, branch_name VARCHAR(150) NOT NULL, address VARCHAR(255), city VARCHAR(100), state VARCHAR(100), country VARCHAR(100) DEFAULT 'India', email VARCHAR(150), phone VARCHAR(20), gst_number VARCHAR(20), status BIT DEFAULT 1, created_at DATETIME2 DEFAULT GETDATE());
CREATE TABLE employees (id BIGINT IDENTITY(1,1) PRIMARY KEY, employee_code VARCHAR(20) NOT NULL UNIQUE, full_name VARCHAR(150) NOT NULL, mobile VARCHAR(20) NOT NULL, email VARCHAR(150), gender VARCHAR(10), date_of_birth DATE, date_of_joining DATE NOT NULL, designation VARCHAR(100), basic_salary DECIMAL(12,2), commission_percentage DECIMAL(5,2) DEFAULT 0, branch_id BIGINT REFERENCES branches(id), status BIT DEFAULT 1, created_at DATETIME2 DEFAULT GETDATE());
CREATE TABLE customers (id BIGINT IDENTITY(1,1) PRIMARY KEY, customer_code VARCHAR(20) NOT NULL UNIQUE, full_name VARCHAR(150) NOT NULL, mobile VARCHAR(20) NOT NULL, email VARCHAR(150), gender VARCHAR(10), date_of_birth DATE, anniversary_date DATE, address VARCHAR(255), membership_type VARCHAR(20) DEFAULT 'NONE', loyalty_points INT DEFAULT 0, branch_id BIGINT REFERENCES branches(id), created_at DATETIME2 DEFAULT GETDATE());
CREATE TABLE services (id BIGINT IDENTITY(1,1) PRIMARY KEY, service_code VARCHAR(20) NOT NULL UNIQUE, service_name VARCHAR(150) NOT NULL, category VARCHAR(100), duration_mins INT, price DECIMAL(10,2) NOT NULL, gst_percentage DECIMAL(5,2) DEFAULT 18, status BIT DEFAULT 1);
CREATE TABLE products (id BIGINT IDENTITY(1,1) PRIMARY KEY, product_code VARCHAR(20) NOT NULL UNIQUE, product_name VARCHAR(150) NOT NULL, brand VARCHAR(100), purchase_price DECIMAL(10,2), selling_price DECIMAL(10,2) NOT NULL, quantity INT DEFAULT 0, reorder_level INT DEFAULT 5, branch_id BIGINT REFERENCES branches(id), status BIT DEFAULT 1);
CREATE TABLE inventory (id BIGINT IDENTITY(1,1) PRIMARY KEY, product_id BIGINT NOT NULL REFERENCES products(id), txn_type VARCHAR(10) NOT NULL, quantity INT NOT NULL, reference VARCHAR(100), txn_date DATETIME2 DEFAULT GETDATE());
CREATE TABLE appointments (id BIGINT IDENTITY(1,1) PRIMARY KEY, appointment_no VARCHAR(20) NOT NULL UNIQUE, customer_id BIGINT NOT NULL REFERENCES customers(id), employee_id BIGINT REFERENCES employees(id), service_id BIGINT NOT NULL REFERENCES services(id), branch_id BIGINT NOT NULL REFERENCES branches(id), appointment_date DATE NOT NULL, appointment_time TIME NOT NULL, status VARCHAR(20) DEFAULT 'BOOKED', notes VARCHAR(500), created_at DATETIME2 DEFAULT GETDATE());
CREATE TABLE invoices (id BIGINT IDENTITY(1,1) PRIMARY KEY, invoice_number VARCHAR(30) NOT NULL UNIQUE, invoice_date DATE NOT NULL DEFAULT CAST(GETDATE() AS DATE), customer_id BIGINT NOT NULL REFERENCES customers(id), employee_id BIGINT REFERENCES employees(id), branch_id BIGINT NOT NULL REFERENCES branches(id), subtotal DECIMAL(12,2) NOT NULL, discount_pct DECIMAL(5,2) DEFAULT 0, discount_amount DECIMAL(12,2) DEFAULT 0, gst_amount DECIMAL(12,2) DEFAULT 0, total_amount DECIMAL(12,2) NOT NULL, payment_method VARCHAR(20), payment_status VARCHAR(20) DEFAULT 'PAID', loyalty_redeemed INT DEFAULT 0, notes VARCHAR(500), created_at DATETIME2 DEFAULT GETDATE());
CREATE TABLE invoice_details (id BIGINT IDENTITY(1,1) PRIMARY KEY, invoice_id BIGINT NOT NULL REFERENCES invoices(id) ON DELETE CASCADE, item_type VARCHAR(10) NOT NULL, item_id BIGINT NOT NULL, item_name VARCHAR(150), qty INT DEFAULT 1, unit_price DECIMAL(10,2), gst_pct DECIMAL(5,2) DEFAULT 0, line_total DECIMAL(12,2));
CREATE TABLE memberships (id BIGINT IDENTITY(1,1) PRIMARY KEY, customer_id BIGINT NOT NULL REFERENCES customers(id), membership_type VARCHAR(20) NOT NULL, start_date DATE NOT NULL, end_date DATE NOT NULL, discount_pct DECIMAL(5,2) DEFAULT 0, status BIT DEFAULT 1);
CREATE TABLE loyalty_points (id BIGINT IDENTITY(1,1) PRIMARY KEY, customer_id BIGINT NOT NULL REFERENCES customers(id), invoice_id BIGINT REFERENCES invoices(id), txn_type VARCHAR(10) NOT NULL, points INT NOT NULL, balance INT NOT NULL, txn_date DATETIME2 DEFAULT GETDATE());
CREATE TABLE expenses (id BIGINT IDENTITY(1,1) PRIMARY KEY, branch_id BIGINT NOT NULL REFERENCES branches(id), expense_date DATE NOT NULL, category VARCHAR(50), amount DECIMAL(12,2) NOT NULL, description VARCHAR(500), created_at DATETIME2 DEFAULT GETDATE());
CREATE TABLE salary (id BIGINT IDENTITY(1,1) PRIMARY KEY, employee_id BIGINT NOT NULL REFERENCES employees(id), salary_month CHAR(7) NOT NULL, basic_salary DECIMAL(12,2), incentive DECIMAL(12,2) DEFAULT 0, commission DECIMAL(12,2) DEFAULT 0, deduction DECIMAL(12,2) DEFAULT 0, final_salary DECIMAL(12,2), payment_date DATE, payment_status VARCHAR(20) DEFAULT 'PENDING', remarks VARCHAR(500));
CREATE INDEX idx_emp_branch ON employees(branch_id);
CREATE INDEX idx_cust_mobile ON customers(mobile);
CREATE INDEX idx_appt_date ON appointments(appointment_date);
CREATE INDEX idx_invoice_date ON invoices(invoice_date);
CREATE INDEX idx_invoice_customer ON invoices(customer_id);
